-- Step 2: get stormflo 200-year (current climate) polygons intersecting Kristiansand bbox
WITH km_bbox AS (
  SELECT ST_MakeEnvelope(62543.56990607368, 6428946.019998128, 107683.72996255726, 6493405.01999838, 25833) AS geom
)
SELECT id, ST_Area(omrade::geometry) AS area, ST_AsText(ST_Envelope(omrade)) AS env_wkt
FROM stormflohavniva_bd7c84ed67254396b81e18b48ee0f525.stormflo200ar_klimaarna s
WHERE EXISTS (
  SELECT 1 FROM km_bbox b WHERE ST_Intersects(s.omrade, b.geom)
)
LIMIT 100;

